1	import { useState, useEffect } from "react";
2	import { View, Text } from "@tarojs/components";
3	import { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, PRESET_DOMAINS, formatDate } from "../../lib";
5	import "./index.scss";
6	
7	interface Habit {
8	  id: string;
9	  title: string;
10	  description: string | null;
11	  domainId: string;
12	  unit: string;
13	  targetValue: number;
14	  isActive: boolean;
15	  logs?: { date: string; completed: boolean; value: number }[];
16	}
17	
18	export default function IndexPage() {
19	  const [habits, setHabits] = useState<Habit[]>([]);
20	  const [loading, setLoading] = useState(true);
21	
22	  useDidShow(() => {
23	    fetchHabits();
24	  });
25	
26	  async function fetchHabits() {
27	    const data = await apiFetch("/api/habits?date=" + getToday());
28	    setHabits(data);
29	    setLoading(false);
30	  }
31	
32	  async function toggleHabit(habitId: string) {
33	    await apiFetch("/api/logs", {
34	      method: "POST",
35	      body: JSON.stringify({ habitId, date: getToday() }),
36	    });
37	    fetchHabits();
38	  }
39	
40	  const completedCount = habits.filter(
41	    (h) => h.logs?.length && h.logs[0]?.completed
42	  ).length;
43	  const totalCount = habits.filter((h) => h.isActive).length;
44	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
45	
46	  return (
47	    <View className="page">
48	      <Text className="header-date">{formatDate(new Date())}</Text>
49	      <Text className="header-title">今日日课</Text>
50	
51	      <View className="progress-card">
52	        <View className="progress-ring">
53	          <View style={{
54	            width: "140rpx", height: "140rpx", borderRadius: "50%",
55	            background: `conic-gradient(#1c1917 ${progressPct * 3.6}deg, #e0dcd5 0deg)`,
56	            display: "flex", alignItems: "center", justifyContent: "center"
57	          }}>
58	            <View style={{
59	              width: "110rpx", height: "110rpx", borderRadius: "50%",
60	              background: "#fff", display: "flex", alignItems: "center", justifyContent: "center"
61	            }}>
62	              <Text className="progress-pct">{progressPct}%</Text>
63	            </View>
64	          </View>
65	        </View>
66	        <View>
67	          <Text className="progress-num">{completedCount}/{totalCount}</Text>
68	          <Text className="progress-label">今日已完成</Text>
69	        </View>
70	      </View>
71	
72	      {PRESET_DOMAINS.map((domain) => {
73	        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
74	        if (domainHabits.length === 0) return null;
75	        return (
76	          <View key={domain.name}>
77	            <Text className="domain-title">{domain.icon} {domain.name}</Text>
78	            {domainHabits.map((habit) => {
79	              const done = !!(habit.logs?.length && habit.logs[0]?.completed);
80	              return (
81	                <View
82	                  key={habit.id}
83	                  className={`habit-item ${done ? "done" : ""}`}
84	                  onClick={() => toggleHabit(habit.id)}
85	                >
86	                  <View className={`check-icon ${done ? "checked" : ""}`}>
87	                    {done && <Text>✓</Text>}
88	                  </View>
89	                  <View className="habit-text">
90	                    <Text className={`habit-name ${done ? "done" : ""}`}>{habit.title}</Text>
91	                    {habit.description && <Text className="habit-desc">{habit.description}</Text>}
92	                  </View>
93	                  <Text className="habit-unit">{habit.targetValue}{habit.unit}</Text>
94	                </View>
95	              );
96	            })}
97	          </View>
98	        );
99	      })}
100	
101	      {totalCount === 0 && (
102	        <View className="empty">
103	          <Text>还没有习惯</Text>
104	          <Text>去「习惯」页面添加吧</Text>
105	        </View>
106	      )}
107	    </View>
108	  );
109	}
