1	import { useState } from "react";
2	import { View, Text, Input } from "@tarojs/components";
3	import { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday } from "../../lib";
5	import "./index.scss";
6	
7	export default function ReviewPage() {
8	  const [form, setForm] = useState({ score: 3, summary: "", highlight: "", lowlight: "", tomorrowGoal: "" });
9	  const [submitted, setSubmitted] = useState(false);
10	  const [aiFeedback, setAiFeedback] = useState("");
11	  const [review, setReview] = useState<any>(null);
12	
13	  useDidShow(() => {
14	    apiFetch(`/api/review?date=${getToday()}`).then((data) => {
15	      if (data?.id) {
16	        setReview(data);
17	        setForm({ score: data.score, summary: data.summary || "", highlight: data.highlight || "", lowlight: data.lowlight || "", tomorrowGoal: data.tomorrowGoal || "" });
18	        setAiFeedback(data.aiFeedback || "");
19	      }
20	    });
21	  });
22	
23	  async function handleSubmit() {
24	    const data = await apiFetch("/api/review", {
25	      method: "POST",
26	      body: JSON.stringify({ ...form, date: getToday() }),
27	    });
28	    setSubmitted(true);
29	    setReview(data);
30	    try {
31	      const ai = await apiFetch("/api/insights", {
32	        method: "POST",
33	        body: JSON.stringify({ type: "review", data: form }),
34	      });
35	      setAiFeedback(ai.text || "");
36	    } catch {}
37	  }
38	
39	  if (review && submitted) {
40	    return (
41	      <View className="page">
42	        <Text className="page-title">每日复盘</Text>
43	        <View className="review-card center">
44	          <Text className="review-score">
45	            {["", "😔", "😐", "🙂", "😊", "🌟"][review.score]}
46	          </Text>
47	          <Text className="review-summary">今日评分 {review.score}/5</Text>
48	          <Text className="review-summary">{review.summary}</Text>
49	        </View>
50	
51	        {aiFeedback ? (
52	          <View className="ai-card">
53	            <Text className="ai-title">⭐ AI 教练点评</Text>
54	            <Text className="ai-text">{aiFeedback}</Text>
55	          </View>
56	        ) : null}
57	
58	        <View className="split-cards">
59	          <View className="split-card">
60	            <Text className="split-label">今日亮点</Text>
61	            <Text className="split-text">{review.highlight || "—"}</Text>
62	          </View>
63	          <View className="split-card">
64	            <Text className="split-label">待改进</Text>
65	            <Text className="split-text">{review.lowlight || "—"}</Text>
66	          </View>
67	        </View>
68	      </View>
69	    );
70	  }
71	
72	  return (
73	    <View className="page">
74	      <Text className="page-title">每日复盘</Text>
75	      <Text className="page-subtitle">三省吾身，日日精进</Text>
76	
77	      <View className="review-card">
78	        <View className="form-group">
79	          <Text className="form-label">今日整体评分</Text>
80	          <View className="stars">
81	            {[1, 2, 3, 4, 5].map((s) => (
82	              <Text key={s} className={`star ${form.score >= s ? "active" : ""}`} onClick={() => setForm({ ...form, score: s })}>⭐</Text>
83	            ))}
84	          </View>
85	        </View>
86	
87	        <View className="form-group">
88	          <Text className="form-label">一句话总结</Text>
89	          <Input className="form-input" placeholder="今天过得怎么样？" value={form.summary} onInput={(e) => setForm({ ...form, summary: e.detail.value })} />
90	        </View>
91	
92	        <View className="form-group">
93	          <Text className="form-label">今日亮点</Text>
94	          <Input className="form-input" placeholder="最值得骄傲的事" value={form.highlight} onInput={(e) => setForm({ ...form, highlight: e.detail.value })} />
95	        </View>
96	
97	        <View className="form-group">
98	          <Text className="form-label">需要改进</Text>
99	          <Input className="form-input" placeholder="可以做得更好的地方" value={form.lowlight} onInput={(e) => setForm({ ...form, lowlight: e.detail.value })} />
100	        </View>
101	
102	        <View className="form-group">
103	          <Text className="form-label">明日目标</Text>
104	          <Input className="form-input" placeholder="明天最重要的三件事" value={form.tomorrowGoal} onInput={(e) => setForm({ ...form, tomorrowGoal: e.detail.value })} />
105	        </View>
106	
107	        <View className="submit-btn" onClick={handleSubmit}><Text>提交复盘</Text></View>
108	      </View>
109	    </View>
110	  );
111	}
