1	import { useState } from "react";
2	import { View, Text } from "@tarojs/components";
3	import { useDidShow } from "@tarojs/taro";
4	import { apiFetch, getToday, PRESET_DOMAINS } from "../../lib";
5	import "./index.scss";
6	
7	interface HabitWithLogs {
8	  id: string;
9	  title: string;
10	  domainId: string;
11	  logs: { date: string; completed: boolean }[];
12	}
13	
14	export default function StatsPage() {
15	  const [habits, setHabits] = useState<HabitWithLogs[]>([]);
16	  const [loading, setLoading] = useState(true);
17	  const [range, setRange] = useState<"week" | "month">("week");
18	
19	  useDidShow(() => { fetchStats(); });
20	
21	  async function fetchStats() {
22	    const data = await apiFetch(`/api/stats?range=${range}`);
23	    setHabits(data.habits || []);
24	    setLoading(false);
25	  }
26	
27	  const totalChecks = habits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
28	  const totalPossible = habits.length * (range === "week" ? 7 : 30);
29	  const overallRate = totalPossible > 0 ? Math.round((totalChecks / totalPossible) * 100) : 0;
30	
31	  const domainStats = PRESET_DOMAINS.map((d) => {
32	    const domainHabits = habits.filter((h) => h.domainId === d.name);
33	    const completed = domainHabits.reduce((sum, h) => sum + h.logs.filter((l) => l.completed).length, 0);
34	    const possible = domainHabits.length * (range === "week" ? 7 : 30);
35	    return { name: d.name, icon: d.icon, rate: possible > 0 ? Math.round((completed / possible) * 100) : 0, color: d.color };
36	  });
37	
38	  // Bar chart data
39	  const days = range === "week" ? 7 : 30;
40	  const barData = Array.from({ length: days }, (_, i) => {
41	    const d = new Date();
42	    d.setDate(d.getDate() - (days - 1 - i));
43	    const dateStr = d.toISOString().split("T")[0];
44	    const completed = habits.filter((h) => h.logs.some((l) => l.date === dateStr && l.completed)).length;
45	    const maxH = habits.length || 1;
46	    return {
47	      label: d.toLocaleDateString("zh-CN", { day: "numeric" }),
48	      completed,
49	      pct: Math.round((completed / maxH) * 100),
50	    };
51	  });
52	
53	  const streakDays = calcStreak(habits);
54	
55	  return (
56	    <View className="page">
57	      <Text className="page-title">数据统计</Text>
58	      <Text className="page-subtitle">看见进步，持续精进</Text>
59	
60	      <View className="range-tabs">
61	        <Text className={`range-tab ${range === "week" ? "active" : ""}`} onClick={() => { setRange("week"); fetchStats(); }}>本周</Text>
62	        <Text className={`range-tab ${range === "month" ? "active" : ""}`} onClick={() => { setRange("month"); fetchStats(); }}>本月</Text>
63	      </View>
64	
65	      <View className="metrics">
66	        <View className="metric"><Text className="metric-value">{overallRate}%</Text><Text className="metric-label">总完成率</Text></View>
67	        <View className="metric"><Text className="metric-value">{totalChecks}</Text><Text className="metric-label">总打卡数</Text></View>
68	        <View className="metric"><Text className="metric-value">{streakDays}</Text><Text className="metric-label">连续天数</Text></View>
69	        <View className="metric"><Text className="metric-value">{habits.length}</Text><Text className="metric-label">活跃习惯</Text></View>
70	      </View>
71	
72	      {/* Bar Chart */}
73	      <View className="chart-card">
74	        <Text className="chart-title">每日完成趋势</Text>
75	        <View className="bar-row">
76	          {barData.map((d, i) => (
77	            <View key={i} className="bar-col">
78	              <View className="bar" style={{ height: `${Math.max(d.pct, 4)}%`, background: d.completed > 0 ? "#1c1917" : "#e0dcd5" }} />
79	              <Text className="bar-label">{d.label}</Text>
80	            </View>
81	          ))}
82	        </View>
83	      </View>
84	
85	      {/* Domain Rates */}
86	      <View className="chart-card">
87	        <Text className="chart-title">领域均衡度</Text>
88	        {domainStats.map((d) => (
89	          <View key={d.name} className="domain-row">
90	            <Text className="domain-name">{d.icon} {d.name}</Text>
91	            <View className="domain-bar-bg">
92	              <View className="domain-bar-fill" style={{ width: `${d.rate}%`, background: d.color }} />
93	            </View>
94	            <Text className="domain-rate">{d.rate}%</Text>
95	          </View>
96	        ))}
97	      </View>
98	    </View>
99	  );
100	}
101	
102	function calcStreak(habits: HabitWithLogs[]): number {
103	  if (habits.length === 0) return 0;
104	  const allDates = new Set<string>();
105	  habits.forEach((h) => h.logs.filter((l) => l.completed).forEach((l) => allDates.add(l.date)));
106	  const sorted = [...allDates].sort().reverse();
107	  let streak = 0;
108	  const today = new Date(getToday());
109	  for (let i = 0; i < sorted.length; i++) {
110	    const expected = new Date(today);
111	    expected.setDate(expected.getDate() - i);
112	    if (sorted[i] === expected.toISOString().split("T")[0]) streak++;
113	    else break;
114	  }
115	  return streak;
116	}
