/* ============================================
   天子日课 — 设计系统
   克制东方美学 · 墨底暖金
   ============================================ */

page {
  /* ---- 色板 ---- */
  --color-bg: #0d0b09;
  --color-surface: #1a1714;
  --color-card: #221e1a;
  --color-card-hover: #2a2520;
  --color-border: #332e28;
  --color-border-light: #3d3730;

  --color-text-primary: #e8e0d6;
  --color-text-secondary: #a89f92;
  --color-text-muted: #7a7268;
  --color-text-inverse: #0d0b09;

  --color-accent: #c4843e;
  --color-accent-light: #d4a05c;
  --color-accent-dark: #a06a2e;
  --color-accent-subtle: rgba(196, 132, 62, 0.12);

  --color-success: #6a8a5a;
  --color-warning: #b8943a;
  --color-danger: #8a4a4a;
  --color-danger-subtle: rgba(138, 74, 74, 0.15);
  --color-info: #4a6a8a;

  /* ---- 圆角 ---- */
  --radius-xs: 6rpx;
  --radius-sm: 12rpx;
  --radius-md: 18rpx;
  --radius-lg: 24rpx;
  --radius-xl: 32rpx;
  --radius-full: 50%;

  /* ---- 间距 ---- */
  --space-xs: 8rpx;
  --space-sm: 12rpx;
  --space-md: 16rpx;
  --space-lg: 24rpx;
  --space-xl: 32rpx;
  --space-2xl: 40rpx;

  /* ---- 字号 ---- */
  --text-xs: 20rpx;
  --text-sm: 24rpx;
  --text-md: 28rpx;
  --text-lg: 32rpx;
  --text-xl: 36rpx;
  --text-2xl: 42rpx;
  --text-3xl: 48rpx;
  --text-title: 56rpx;

  /* ---- 基础 ---- */
  background: var(--color-bg);
  color: var(--color-text-primary);
  font-family: -apple-system, "PingFang SC", "Noto Sans SC", "Helvetica Neue", sans-serif;
  font-size: var(--text-md);
  line-height: 1.7;
}

/* ============================================
   全局组件类
   ============================================ */

.page {
  padding: var(--space-lg);
  padding-bottom: calc(var(--space-lg) + 120rpx);
}

/* ---- 卡片 ---- */
.card {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-xl);
  margin-top: var(--space-lg);
}

/* ---- 标题 ---- */
.page-title {
  display: block;
  font-size: var(--text-3xl);
  font-weight: 600;
  color: var(--color-text-primary);
  letter-spacing: 0.03em;
}

.page-subtitle {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  margin-top: var(--space-xs);
  letter-spacing: 0.05em;
}

/* ---- 表单 ---- */
.form-group {
  margin-bottom: var(--space-lg);
}

.form-label {
  display: block;
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-text-secondary);
  margin-bottom: var(--space-xs);
  letter-spacing: 0.02em;
}

.form-input {
  width: 100%;
  height: 76rpx;
  border-radius: var(--radius-sm);
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  padding: 0 var(--space-md);
  font-size: var(--text-md);
  color: var(--color-text-primary);
  box-sizing: border-box;
}

.form-input:focus,
.form-input:active {
  border-color: var(--color-accent);
}

.form-textarea {
  width: 100%;
  min-height: 140rpx;
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-sm);
  padding: var(--space-md);
  font-size: var(--text-md);
  color: var(--color-text-primary);
  box-sizing: border-box;
  line-height: 1.6;
}

.form-row {
  display: flex;
  gap: var(--space-lg);
}

.flex-1 {
  flex: 1;
}

.form-picker {
  width: 100%;
  height: 76rpx;
  border-radius: var(--radius-sm);
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  padding: 0 var(--space-md);
  font-size: var(--text-md);
  color: var(--color-text-primary);
  display: flex;
  align-items: center;
  box-sizing: border-box;
}

.form-buttons {
  display: flex;
  gap: var(--space-md);
  margin-top: var(--space-xl);
}

.btn-cancel {
  flex: 1;
  height: 80rpx;
  border-radius: var(--radius-md);
  border: 1rpx solid var(--color-border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--text-md);
  color: var(--color-text-secondary);
  background: transparent;
}

.btn-save {
  flex: 1;
  height: 80rpx;
  border-radius: var(--radius-md);
  background: var(--color-accent);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: var(--text-md);
  color: var(--color-text-inverse);
  font-weight: 500;
}

.btn-save.disabled {
  opacity: 0.5;
}

/* ---- 弹窗 ---- */
.modal-mask {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.72);
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: center;
}

.modal {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  width: 630rpx;
  border-radius: var(--radius-xl);
  padding: var(--space-xl);
  max-height: 80vh;
  overflow: auto;
}

.modal-title {
  display: block;
  font-size: var(--text-xl);
  font-weight: 600;
  color: var(--color-text-primary);
  margin-bottom: var(--space-xl);
  letter-spacing: 0.02em;
}

/* ---- 空状态 ---- */
.empty {
  text-align: center;
  padding: var(--space-2xl) 0;
  color: var(--color-text-muted);
  font-size: var(--text-md);
  line-height: 2;
}

/* ============================================
   今日仪表盘 - 天子日课
   ============================================ */

/* ---- 日期标题 ---- */
.header-date {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  letter-spacing: 0.06em;
  margin-bottom: var(--space-xs);
}

.header-title {
  display: block;
  font-size: var(--text-title);
  font-weight: 700;
  color: var(--color-text-primary);
  letter-spacing: 0.04em;
  line-height: 1.2;
}

/* ---- 进度卡片 ---- */
.progress-card {
  background: linear-gradient(135deg, var(--color-card) 0%, #1a1612 100%);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-xl);
  padding: var(--space-xl);
  display: flex;
  align-items: center;
  gap: var(--space-xl);
  margin-top: var(--space-xl);
  position: relative;
  overflow: hidden;
}

.progress-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 2rpx;
  background: linear-gradient(90deg, transparent, var(--color-accent-subtle), transparent);
}

.progress-ring {
  position: relative;
  width: 140rpx;
  height: 140rpx;
  flex-shrink: 0;
}

.progress-pct {
  font-size: var(--text-lg);
  font-weight: 700;
  color: var(--color-text-primary);
  letter-spacing: 0.02em;
}

.progress-info {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.progress-num {
  font-size: var(--text-2xl);
  font-weight: 600;
  color: var(--color-text-primary);
  letter-spacing: 0.02em;
}

.progress-label {
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  letter-spacing: 0.04em;
}

/* ---- 领域分组 ---- */
.domain-section {
  margin-top: var(--space-xl);
}

.domain-title {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
  letter-spacing: 0.04em;
  padding-left: var(--space-md);
  border-left: 3rpx solid var(--color-accent);
}

/* ---- 习惯条目 ---- */
.habit-item {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  margin-bottom: var(--space-sm);
  display: flex;
  align-items: center;
